import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from './contexts/AuthContext';
import Login from './components/Login';
import Register from './components/Register';
import Calendar from './components/Calendar';
import HolidayManagement from './components/HolidayManagement';
import VacationForm from './components/VacationForm';
import VacationPlanner from './components/VacationPlanner';
import NationalHolidays from './components/NationalHolidays';
import './App.css';
// import './calendar-tailwind.css'; // Temporarily disabled to fix CSS conflicts

function App() {
  const { user, token, loading, logout, fetchUserProfile } = useAuth();
  const [officialHolidays, setOfficialHolidays] = useState([]);
  const [vacations, setVacations] = useState([]);
  const [showLogin, setShowLogin] = useState(true);

  const API_BASE_URL = 'http://localhost:8000';

  const fetchOfficialHolidays = useCallback(async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/holidays`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      if (response.ok) {
        const data = await response.json();
        setOfficialHolidays(data);
      }
    } catch (error) {
      console.error('Error fetching holidays:', error);
    }
  }, [token]);

  const fetchVacations = useCallback(async () => {
    try {
      console.log('Fetching vacations from:', `${API_BASE_URL}/vacations`);
      const response = await fetch(`${API_BASE_URL}/vacations`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      if (response.ok) {
        const data = await response.json();
        console.log('Vacations fetched successfully:', data);
        setVacations(data);
      } else {
        console.error('Failed to fetch vacations:', response.status, response.statusText);
      }
    } catch (error) {
      console.error('Error fetching vacations:', error);
    }
  }, [token, API_BASE_URL]);

  useEffect(() => {
    if (user && token) {
      fetchUserProfile();
      fetchOfficialHolidays();
      fetchVacations();
    }
  }, [user, token, fetchUserProfile, fetchOfficialHolidays, fetchVacations]);

  if (loading) {
    return <div>Loading...</div>;
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
        <div className="sm:mx-auto sm:w-full sm:max-w-md">
          <h2 className="mt-6 text-center text-3xl font-extrabold text-gray-900">
            Leave Tracking App
          </h2>
        </div>
        <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md">
          {showLogin ? (
            <>
              <Login />
              <div className="text-center mt-4">
                <p className="text-sm text-gray-600">
                  Don't have an account?{' '}
                  <button
                    onClick={() => setShowLogin(false)}
                    className="font-medium text-indigo-500"
                  >
                    Create one here
                  </button>
                </p>
              </div>
            </>
          ) : (
            <>
              <Register />
              <div className="text-center mt-4">
                <p className="text-sm text-gray-600">
                  Already have an account?{' '}
                  <button
                    onClick={() => setShowLogin(true)}
                    className="font-medium text-indigo-600 hover:text-indigo-500"
                  >
                    Sign in here
                  </button>
                </p>
              </div>
            </>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white shadow">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center py-6">
            <h1 className="text-3xl font-bold text-gray-900">
              Welcome, {user.name}!
            </h1>
            <div className="flex items-center space-x-4">
              {/* Backend Status Indicator */}
              <div className="flex items-center space-x-2">
                <div className="w-3 h-3 bg-green-500 rounded-full animate-pulse"></div>
                <span className="text-sm text-gray-600">Backend</span>
              </div>
              <button
                onClick={logout}
                className="bg-red-600 hover:bg-red-700 text-white font-bold py-2 px-4 rounded"
              >
                Logout
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
        <div className="px-4 py-6 sm:px-0">
          {/* Two Column Layout */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            {/* Left Column - Calendar & Holiday Management */}
            <div className="space-y-6">
              {/* Calendar Section */}
              <div className="bg-white rounded-lg shadow">
                <Calendar
                  holidays={officialHolidays}
                  vacations={vacations}
                  onNavigate={(action) => {
                    if (action === 'PREV') {
                      // Handle previous month
                    } else if (action === 'NEXT') {
                      // Handle next month
                    }
                  }}
                  currentDate={new Date()}
                  onViewChange={(view) => {
                    // Handle view change
                  }}
                />
              </div>

              {/* National Holidays Section */}
              <NationalHolidays
                API_BASE_URL={API_BASE_URL}
                token={token}
                onAddHoliday={async (holidayData) => {
                  try {
                    const response = await fetch(`${API_BASE_URL}/holidays`, {
                      method: 'POST',
                      headers: {
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${token}`
                      },
                      body: JSON.stringify(holidayData)
                    });
                    if (response.ok) {
                      // Refresh holidays
                      fetchOfficialHolidays();
                    }
                  } catch (error) {
                    console.error('Error adding national holiday:', error);
                  }
                }}
              />

              {/* Holiday Management Section */}
              <HolidayManagement
                holidays={officialHolidays}
                onAddHoliday={async (holidayData) => {
                  try {
                    const response = await fetch(`${API_BASE_URL}/holidays`, {
                      method: 'POST',
                      headers: {
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${token}`
                      },
                      body: JSON.stringify(holidayData)
                    });
                    if (response.ok) {
                      // Refresh holidays
                      fetchOfficialHolidays();
                    }
                  } catch (error) {
                    console.error('Error adding holiday:', error);
                  }
                }}
                onDeleteHoliday={async (holidayId) => {
                  try {
                    const response = await fetch(`${API_BASE_URL}/holidays/${holidayId}`, {
                      method: 'DELETE',
                      headers: {
                        'Authorization': `Bearer ${token}`
                      }
                    });
                    if (response.ok) {
                      // Refresh holidays
                      fetchOfficialHolidays();
                    }
                  } catch (error) {
                    console.error('Error deleting holiday:', error);
                  }
                }}
              />

              {/* Vacation Form Section */}
              <VacationForm
                onAddVacation={async (vacationData) => {
                  try {
                    console.log('Submitting vacation:', vacationData);
                    const response = await fetch(`${API_BASE_URL}/vacations`, {
                      method: 'POST',
                      headers: {
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${token}`
                      },
                      body: JSON.stringify(vacationData)
                    });
                    if (response.ok) {
                      const newVacation = await response.json();
                      console.log('Vacation added successfully:', newVacation);
                      // Refresh vacations
                      fetchVacations();
                    } else {
                      console.error('Failed to add vacation:', response.status, response.statusText);
                    }
                  } catch (error) {
                    console.error('Error adding vacation:', error);
                  }
                }}
              />
            </div>

            {/* Right Column - Vacation Planner */}
            <div>
              <VacationPlanner
                holidays={officialHolidays}
                vacations={vacations}
                leaveBalances={{
                  EL: 30,
                  SL: 6,
                  CL: 3
                }}
              />
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}

export default App;
